const API_BASE_URL = 'http://localhost:5000';

export const api = {
    analyzeGap: async (file: File, jobDescription: string) => {
        const formData = new FormData();
        formData.append('file', file);
        formData.append('jobDescription', jobDescription);

        // Note: The backend endpoint name might need to be adjusted if it was /analyze-gap-v2 previously.
        // Based on current main.py, we only have /extract-text logic or similar. 
        // We will assume the extraction endpoint is what's intended or update accordingly.
        // For now, keeping as is but pointing to correct port.
        const response = await fetch(`${API_BASE_URL}/analyze`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ resume_text: "tbd", job_description: jobDescription }),
        });

        if (!response.ok) {
            const errorData = await response.json().catch(() => ({}));
            throw new Error(errorData.error || 'Failed to analyze gap');
        }

        return response.json();
    },

    startInterview: async () => {
        const response = await fetch(`${API_BASE_URL}/start-interview`, {
            method: 'POST',
        });
        if (!response.ok) throw new Error('Failed to start interview');
        return response.json();
    },

    chat: async (message: string, sessionId?: string) => {
        const response = await fetch(`${API_BASE_URL}/chat`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ message, session_id: sessionId })
        });

        if (!response.ok) {
            throw new Error('Chat failed');
        }

        return response.json();
    },

    endInterview: async (sessionId: string) => {
        const response = await fetch(`${API_BASE_URL}/feedback`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ session_id: sessionId })
        });
        if (!response.ok) throw new Error('Failed to end interview');
        return response.json();
    },

    executeCode: async (code: string, language: string = 'javascript') => {
        const response = await fetch(`${API_BASE_URL}/execute-code`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ code, language })
        });
        if (!response.ok) throw new Error('Failed to execute code');
        return response.json();
    }
};
